# Description: BiZ9 Framework: Mongo-DB-Dump
source biz9_config
echo "#################"
echo "BiZ9 Framework Mongo Table Dump"
echo "#################"
bash ${BIZ9_SCRIPTZ_DIRECTORY}view_git_sub_header.sh

folder_path="dumps/${APP_ID}"-"$(date +%F-%H-%M-%S).gz"

mongodump --db=${APP_ID}  --gzip --archive=${folder_path} --port 27019

bash ${BIZ9_SCRIPTZ_DIRECTORY}view_footer.sh
exit
